import type { Context } from "hono";
import type { Env } from "../types/env.js";
import { getPrisma } from "../config/database.js";
import { serialize } from "../lib/serializer.js";

export const getAppointments = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const appointments = await prisma.appointment.findMany({
      orderBy: [{ date: "desc" }, { startTime: "asc" }],
    });
    return c.json(serialize(appointments));
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const createAppointment = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const {
      clientId,
      therapistId,
      service,
      serviceIcon,
      startTime,
      endTime,
      date,
      price,
      notes,
    } = await c.req.json();

    if (!clientId || !therapistId || !startTime || !date) {
      return c.json(
        {
          error:
            "Thiếu thông tin đặt lịch bắt buộc (Mã KH, Mã KTV, Ngày hẹn, Giờ bắt đầu)",
        },
        400
      );
    }

    // Verify Client exists
    const dbClient = await prisma.client.findUnique({ where: { id: clientId } });
    if (!dbClient) {
      return c.json({ error: "Khách hàng không tồn tại" }, 404);
    }

    // Verify Therapist exists
    const dbTherapist = await prisma.therapist.findUnique({
      where: { id: therapistId },
    });
    if (!dbTherapist) {
      return c.json({ error: "Nhân viên không tồn tại" }, 404);
    }

    const apptPrice = BigInt(price || 0);

    // Create appointment + update client stats + create notification in a transaction
    const [appointment] = await prisma.$transaction([
      prisma.appointment.create({
        data: {
          clientId,
          clientName: dbClient.name,
          clientTier: dbClient.tier,
          clientAvatar: dbClient.avatar,
          service: service || null,
          serviceIcon: serviceIcon || null,
          therapist: dbTherapist.name,
          therapistId,
          startTime,
          endTime: endTime || startTime,
          date,
          status: "confirmed",
          statusLabel: "Đã xác nhận",
          price: apptPrice,
          notes: notes || null,
        },
      }),
      prisma.client.update({
        where: { id: clientId },
        data: {
          totalVisits: { increment: 1 },
          totalSpent: { increment: apptPrice },
          memberPoints: { increment: Math.floor(Number(apptPrice) / 10000) },
          lastVisit: date,
        },
      }),
      prisma.notification.create({
        data: {
          type: "success",
          title: "Đã tạo lịch hẹn mới",
          message: `${dbClient.name} đã đặt lịch lúc ${startTime}`,
          time: "Vừa xong",
          read: false,
          priority: "normal",
        },
      }),
    ]);

    return c.json(serialize(appointment), 201);
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const updateAppointment = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const id = c.req.param("id");
    const {
      service,
      serviceIcon,
      price,
      date,
      startTime,
      endTime,
      therapistId,
      notes,
      status,
    } = await c.req.json();

    const dbAppt = await prisma.appointment.findUnique({ where: { id } });
    if (!dbAppt) {
      return c.json({ error: "Lịch hẹn không tồn tại" }, 404);
    }

    const updateData: Record<string, unknown> = {};
    if (service !== undefined) updateData.service = service;
    if (serviceIcon !== undefined) updateData.serviceIcon = serviceIcon;
    if (price !== undefined) updateData.price = BigInt(price || 0);
    if (date !== undefined) updateData.date = date;
    if (startTime !== undefined) updateData.startTime = startTime;
    if (endTime !== undefined) updateData.endTime = endTime;
    if (notes !== undefined) updateData.notes = notes;

    if (status !== undefined) {
      updateData.status = status;
      const labels: Record<string, string> = {
        in_progress: "Đang xử lý",
        completed: "Hoàn tất",
        cancelled: "Đã hủy",
        confirmed: "Đã xác nhận",
      };
      updateData.statusLabel = labels[status] || "Đã xác nhận";
    }

    if (therapistId) {
      const dbTherapist = await prisma.therapist.findUnique({
        where: { id: therapistId },
      });
      if (!dbTherapist) {
        return c.json({ error: "Nhân viên không tồn tại" }, 404);
      }
      updateData.therapistId = therapistId;
      updateData.therapist = dbTherapist.name;
    }

    const updated = await prisma.appointment.update({
      where: { id },
      data: updateData,
    });

    return c.json(serialize(updated));
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const updateAppointmentStatus = async (
  c: Context<{ Bindings: Env }>
) => {
  try {
    const prisma = getPrisma(c.env);
    const id = c.req.param("id");
    const { status } = await c.req.json();

    if (!status) {
      return c.json({ error: "Trạng thái là bắt buộc" }, 400);
    }

    const labels: Record<string, string> = {
      in_progress: "Đang xử lý",
      completed: "Hoàn tất",
      cancelled: "Đã hủy",
      confirmed: "Đã xác nhận",
    };

    const appointment = await prisma.appointment.update({
      where: { id },
      data: { status, statusLabel: labels[status] || "Đã xác nhận" },
    });

    return c.json(serialize(appointment));
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const deleteAppointment = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const id = c.req.param("id");
    await prisma.appointment.delete({ where: { id } });
    return c.json({ success: true, message: "Đã xóa lịch hẹn" });
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};
